head.b:skin:
/* Blogger theme resets and structural skin content */
body {
  margin: 0;
  padding: 0;
}

body.script:
//

// API GATEWAY CONFIGURATION - HARDCODED LIVE API URL
const API_BASE_URL = 'https://marketplace-kt-brm.vercel.app';

let cachedListings = [];
let base64FotoData = '';

// Handle splash page display
document.addEventListener('DOMContentLoaded', () => {
  initWelcomeScreen();
  loadMarketplaceData();
});

function initWelcomeScreen() {
  const welcome = document.getElementById('welcome-screen');
  const isDismissed = sessionStorage.getItem('pasardomba_welcome_dismissed') === 'true';
  if (isDismissed) {
    if (welcome) welcome.style.display = 'none';
  }
}

function enterApp() {
  const welcome = document.getElementById('welcome-screen');
  if (welcome) {
    welcome.style.opacity = '0';
    welcome.style.transform = 'scale(1.03)';
    sessionStorage.setItem('pasardomba_welcome_dismissed', 'true');
    setTimeout(() => {
      welcome.style.display = 'none';
    }, 500);
  }
}

// Fetch catalog listings from server
async function loadMarketplaceData() {
  showLoading(true);
  showError(false);
  showEmpty(false);
  try {
    const response = await fetch(API_BASE_URL + '/api/market');
    if (!response.ok) {
      throw new Error('Koneksi server gagal dengan status: ' + response.status);
    }
    cachedListings = await response.json();
    applyFilters();
  } catch (err) {
    console.error('Error fetching data:', err);
    showError(true, err.message || 'Gagal tersambung dengan server database.');
  } finally {
    showLoading(false);
  }
}

// Apply Filter & Search query checks
function applyFilters() {
  const searchQuery = document.getElementById('searchInput').value.toLowerCase().trim();
  const selectedBreed = document.getElementById('breedFilter').value;

  const filtered = cachedListings.filter(item => {
    const matchSearch = item.jenis_ras.toLowerCase().includes(searchQuery) || 
                        item.nama_penjual.toLowerCase().includes(searchQuery) ||
                        item.alamat_penjual.toLowerCase().includes(searchQuery);
    const matchBreed = selectedBreed === '' || item.jenis_ras === selectedBreed;
    return matchSearch && matchBreed;
  });

  renderShowcaseGrid(filtered);
}

// Render Showcase listings
function renderShowcaseGrid(items) {
  const grid = document.getElementById('listingsGrid');
  grid.innerHTML = '';

  if (items.length === 0) {
    showEmpty(true);
    return;
  } else {
    showEmpty(false);
  }

  items.forEach(item => {
    const isSold = item.status === 'Terjual';
    const formattedPrice = formatRupiah(item.harga);

    // Prepare URL-encoded text routing directly to that specific seller's WhatsApp
    const waText = 'Halo Pak/Bu ' + item.nama_penjual + ', saya tertarik dengan Domba ' + item.jenis_ras + ' seharga ' + formattedPrice + ' yang diiklankan di Pasar Domba Bagus Rejo Mulyo. Apakah masih tersedia?';

    // Clean WhatsApp number format (remove non-numbers, replace leading 0 with country code 62)
    let cleanWA = item.whatsapp_penjual.replace(/\D/g, '');
    if (cleanWA.startsWith('0')) {
      cleanWA = '62' + cleanWA.substring(1);
    }
    const waUrl = 'https://wa.me/' + cleanWA + '?text=' + encodeURIComponent(waText);

    const card = document.createElement('div');
    card.className = 'fade-in relative bg-white rounded-3xl overflow-hidden shadow-md hover:shadow-xl transition-all duration-300 border border-gray-100 flex flex-col h-full group ' + (isSold ? 'opacity-75' : '');

    card.innerHTML = `
      <!-- Card Image Thumbnail -->
      <div class="relative w-full h-52 bg-gray-150 overflow-hidden">
        <img src="${item.foto_url || 'https://images.unsplash.com/photo-1484557985045-edf25e08da73?auto=format&fit=crop&w=800&q=80'}" 
             alt="${item.jenis_ras}" 
             class="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />

        <!-- Status Mask Overlay for sold items -->
        ${isSold ? `
          <div class="absolute inset-0 bg-gray-900/70 backdrop-blur-[2px] flex items-center justify-center z-10">
            <span class="bg-red-650 text-white font-outfit text-lg font-extrabold tracking-wider px-5 py-2 rounded-2xl shadow-xl border border-red-500 transform -rotate-6 uppercase">
              Terjual
            </span>
          </div>
        ` : ''}
      </div>

      <!-- Card Content Body -->
      <div class="p-4 sm:p-6 flex-grow flex flex-col justify-between">
        <div>
          <h3 class="font-outfit text-lg sm:text-xl font-bold text-gray-800 leading-tight mb-2">${item.jenis_ras}</h3>

          <!-- Owner & Address displays (Prominently show Owner Name & Address) -->
          <div class="flex flex-col gap-1.5 mb-4 bg-gray-50 px-3.5 py-2.5 rounded-xl border border-gray-150 text-xs">
            <div class="flex items-center gap-2">
              <span class="text-sm">👤</span>
              <span class="text-gray-500 font-medium">Pemilik: 
                <strong class="text-gray-800 font-semibold">${item.nama_penjual}</strong>
              </span>
            </div>
            <div class="flex items-start gap-2 pt-1.5 border-t border-gray-200/50">
              <span class="text-sm">📍</span>
              <span class="text-gray-500 font-medium">Alamat: 
                <strong class="text-gray-850 font-semibold">${item.alamat_penjual}</strong>
              </span>
            </div>
          </div>

          <!-- Product Specs -->
          <div class="grid grid-cols-2 gap-3 mb-4 text-xs">
            <div class="bg-forest-50 p-2.5 rounded-xl border border-forest-100/50">
              <span class="block text-gray-400 font-medium mb-0.5">Estimasi Bobot</span>
              <span class="font-bold text-forest-900 text-sm font-outfit">${item.bobot_kg} kg</span>
            </div>
            <div class="bg-amberAccent-50 p-2.5 rounded-xl border border-amberAccent-100/50">
              <span class="block text-gray-400 font-medium mb-0.5">WhatsApp</span>
              <span class="font-bold text-amberAccent-900 text-sm font-outfit">${item.whatsapp_penjual}</span>
            </div>
          </div>
        </div>

        <div>
          <!-- Price Display -->
          <div class="mb-4 flex flex-col">
            <span class="text-xs text-gray-400 font-medium">Harga Domba</span>
            <span class="text-xl sm:text-2xl font-black font-outfit ${isSold ? 'text-gray-400 line-through' : 'text-forest-700'}">
              ${formattedPrice}
            </span>
          </div>

          <!-- Action buttons - finger friendly height (h-12) -->
          ${isSold ? `
            <button disabled="disabled" class="w-full h-12 bg-gray-200 text-gray-400 font-semibold rounded-xl text-sm cursor-not-allowed flex items-center justify-center gap-2">
              🚫 Hubungi Pemilik (Terjual)
            </button>
          ` : `
            <a href="${waUrl}" target="_blank" rel="noopener noreferrer" class="w-full h-12 bg-emerald-600 hover:bg-emerald-700 active:scale-[0.98] text-white font-bold rounded-xl text-sm text-center flex items-center justify-center gap-2 transition duration-200 shadow-md shadow-emerald-600/10">
              💬 Hubungi Pemilik (WhatsApp)
            </a>
          `}

          <!-- Management actions (Mark as sold & Delete) - finger friendly height (h-11) -->
          <div class="flex gap-2 mt-3 pt-3 border-t border-gray-100">
            ${!isSold ? `
              <button onclick="markListingAsSold(${item.id})" class="flex-1 h-11 bg-amber-500 hover:bg-amber-600 active:scale-[0.97] text-white font-semibold text-xs rounded-lg text-center transition duration-150 flex items-center justify-center gap-1 shadow-sm">
                ✓ Tandai Terjual
              </button>
            ` : ''}
            <button onclick="deleteListingRow(${item.id})" class="flex-grow h-11 bg-red-50 hover:bg-red-100 hover:text-red-700 active:scale-[0.97] text-red-655 font-semibold text-xs rounded-lg text-center transition duration-150 flex items-center justify-center gap-1 border border-red-200">
              🗑️ Hapus
            </button>
          </div>
        </div>
      </div>
    `;
    grid.appendChild(card);
  });
}

// Modal view handlers
function openAddListingModal() {
  document.getElementById('addListingModal').classList.remove('hidden');
  document.body.style.overflow = 'hidden';
}

// Close Modal View helper
function closeAddListingModal() {
  document.getElementById('addListingModal').classList.add('hidden');
  document.body.style.overflow = '';
  document.getElementById('addListingForm').reset();
  removeUploadedFoto();
}

// Image Upload Base64 Converter
function handleFotoChange(e) {
  const file = e.target.files[0];
  if (!file) return;

  // Limit check (max 3MB)
  if (file.size > 3 * 1024 * 1024) {
    showToast('Unggahan Gagal', 'Ukuran foto maksimal adalah 3MB.', 'error');
    e.target.value = '';
    return;
  }

  const reader = new FileReader();
  reader.onload = function(evt) {
    base64FotoData = evt.target.result;
    document.getElementById('uploadPrompt').classList.add('hidden');
    document.getElementById('previewContainer').classList.remove('hidden');
    document.getElementById('fotoPreview').src = base64FotoData;
  };
  reader.readAsDataURL(file);
}

// Remove photo helper
function removeUploadedFoto() {
  base64FotoData = '';
  document.getElementById('fotoInput').value = '';
  document.getElementById('uploadPrompt').classList.remove('hidden');
  document.getElementById('previewContainer').classList.add('hidden');
  document.getElementById('fotoPreview').src = '#';
}

// Submit New Entry Form
async function submitAddListing(e) {
  e.preventDefault();

  const submitBtn = document.getElementById('submitBtn');
  submitBtn.disabled = true;
  submitBtn.innerHTML = 'Menyimpan... ⏳';

  const payload = {
    nama_penjual: document.getElementById('namaPenjual').value.trim(),
    alamat_penjual: document.getElementById('alamatPenjual').value.trim(),
    jenis_ras: document.getElementById('jenisRas').value,
    bobot_kg: parseFloat(document.getElementById('bobotKg').value),
    harga: parseInt(document.getElementById('harga').value),
    whatsapp_penjual: document.getElementById('whatsappPenjual').value.trim(),
    foto_url: base64FotoData
  };

  try {
    const response = await fetch(API_BASE_URL + '/api/market', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });

    if (!response.ok) {
      const errData = await response.json();
      throw new Error(errData.message || 'Gagal menyimpan data.');
    }

    showToast('Sukses', 'Iklan domba berhasil dipublikasikan!', 'success');
    closeAddListingModal();
    loadMarketplaceData();
  } catch (err) {
    console.error('Error posting listing:', err);
    showToast('Posting Gagal', err.message || 'Terjadi kesalahan sistem backend.', 'error');
  } finally {
    submitBtn.disabled = false;
    submitBtn.innerHTML = 'Pasang Iklan';
  }
}

// Update Item Status (PUT)
async function markListingAsSold(id) {
  if (!confirm('Apakah Anda yakin ingin menandai domba ini sebagai Terjual?')) return;

  try {
    const response = await fetch(API_BASE_URL + '/api/market/' + id + '/status', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'Terjual' })
    });

    if (!response.ok) {
      throw new Error('Gagal mengupdate status ke database.');
    }

    showToast('Sukses', 'Domba berhasil ditandai sebagai TERJUAL.', 'success');
    loadMarketplaceData();
  } catch (err) {
    console.error('Error updating status:', err);
    showToast('Gagal Update', err.message || 'Terjadi kesalahan database.', 'error');
  }
}

// Delete listing row completely (DELETE)
async function deleteListingRow(id) {
  if (!confirm('Apakah Anda yakin ingin menghapus posting jualan ini secara permanen dari database?')) return;

  try {
    const response = await fetch(API_BASE_URL + '/api/market/' + id, {
      method: 'DELETE'
    });

    if (!response.ok) {
      throw new Error('Gagal menghapus data dari database.');
    }

    showToast('Sukses', 'Iklan domba berhasil dihapus secara permanen.', 'success');
    loadMarketplaceData();
  } catch (err) {
    console.error('Error deleting listing:', err);
    showToast('Gagal Hapus', err.message || 'Terjadi kesalahan database.', 'error');
  }
}

// Helper UI controllers
function showLoading(show) {
  document.getElementById('loadingState').classList.toggle('hidden', !show);
  if (show) {
    document.getElementById('listingsGrid').innerHTML = '';
  }
}

// Show connection error
function showError(show, msg = '') {
  document.getElementById('errorState').classList.toggle('hidden', !show);
  if (show) {
    document.getElementById('errorMessage').textContent = msg;
    document.getElementById('listingsGrid').innerHTML = '';
  }
}

// Show empty page info
function showEmpty(show) {
  document.getElementById('emptyState').classList.toggle('hidden', !show);
}

// Format number to Rupiah
function formatRupiah(amount) {
  const number = Number(amount);
  if (isNaN(number)) return 'Rp 0';
  return 'Rp ' + number.toLocaleString('id-ID');
}

// Trigger toast alerts
function showToast(title, message, type = 'success') {
  const toast = document.getElementById('toast');
  const toastIcon = document.getElementById('toastIcon');
  const toastTitle = document.getElementById('toastTitle');
  const toastMessage = document.getElementById('toastMessage');

  toastTitle.textContent = title;
  toastMessage.textContent = message;

  if (type === 'success') {
    toast.className = 'fixed bottom-5 right-5 z-50 max-w-sm w-full bg-white rounded-xl shadow-2xl border-l-4 border-emerald-650 p-4 transform translate-y-0 opacity-100 transition-all duration-300 flex items-start gap-3';
    toastIcon.textContent = '✅';
  } else {
    toast.className = 'fixed bottom-5 right-5 z-50 max-w-sm w-full bg-white rounded-xl shadow-2xl border-l-4 border-red-655 p-4 transform translate-y-0 opacity-100 transition-all duration-300 flex items-start gap-3';
    toastIcon.textContent = '⚠️';
  }

  // Automatically hide after 4 seconds
  setTimeout(() => {
    toast.className = 'fixed bottom-5 right-5 z-50 max-w-sm w-full bg-white rounded-xl shadow-2xl border-l-4 border-forest-600 p-4 transform translate-y-24 opacity-0 transition-all duration-300 pointer-events-none flex items-start gap-3';
  }, 4000);
}

//
